// NODO: Welcome (v2.7) - Dynamic Pro & Guest UI (ASH & KEYBOARD FIXED)
const item = $input.first().json;
const owner = item.owner_data || {};
const config = owner.customer_bot_config || {};
const msg = item.body.message;
const session = item.active_session || {};
const stakeholder = item.stakeholder;
const isSubscribed = session.preferences?.broadcast_subscribed || false;

// 1. CONFIGURAZIONE SICUREZZA ASH (LOGICA ORIGINALE)
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const WEBHOOK_ID = '8eb69e84-d20d-486e-a70e-9acf31c3da9e';
const chatId = msg.chat.id.toString();
const timestamp = Date.now().toString();

const payload = `${owner.chat_id}|${chatId}|${timestamp}|${WEBHOOK_ID}`;

function generateSignature(str, key) {
    let hash = 0;
    const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const signature = generateSignature(payload, SECRET_KEY);
const ash = `${Buffer.from(payload).toString('base64')}.${signature}`;
const registerUrl = `https://dashboard.trinai.it/register?ash=${ash}`;
const dashboardUrl = "https://dashboard.trinai.it/";
const BASE_APP_URL = item.urlMiniApp || "https://trinaibusinessoperatingsystem.github.io/SiteBoS-MiniApp";
const ashToken = `?ash=${ash}`;
const privacyUrl = (item.urlMiniApp || "https://dashboard.trinai.it/") + "legal.html";

// 2. TASTO ETICO DINAMICO
const offerButton = isSubscribed 
    ? { text: "🔕 Disattiva Offerte", callback_data: "u_TOGGLE_OFFERS" } 
    : { text: "🔔 Attiva Offerte", callback_data: "u_TOGGLE_OFFERS" };

// 3. DATI PER IL MESSAGGIO
const isPro = !!(stakeholder && stakeholder.metadata && stakeholder.metadata.status !== "GUEST");
const customerName = stakeholder?.user_ref?.nome || msg.from.first_name || "Gentile Ospite";
const agentName = config.identity?.agent_name || "Assistente Virtuale";
const businessDesc = owner.business_description || "";

// 4. DIDASCALIA FUNZIONI CORE AI
const aiFunctionsDidascalia = `
📊 <b>Preventivatore:</b> Quotazioni e analisi costi in tempo reale.
📅 <b>Appuntamenti:</b> Gestione booking e prenotazione consulenze.`;

// 5. COSTRUZIONE DEL MESSAGGIO E TASTIERA DINAMICA (GUEST VS PRO)
let messageText = "";
let inlineKeyboard = [];

if (!isPro) {
    // ━━━ VERSIONE GUEST ━━━
    messageText = `👋 <b>Ciao ${customerName}!</b>\n━━━━━━━━━━━━━━━━━━━━\nBenvenuto. Sono <b>${agentName}</b>, l'assistente ufficiale di <b>${owner.ragione_sociale}</b>. \n\n🎯 <b>Cosa Facciamo?:</b>\n<i>\"${businessDesc}\"</i>\n\n⚠️ <b>FUNZIONI AI DISABILITATE:</b>\nLe seguenti funzioni richiedono la registrazione su <b>TrinAi</b>:\n${aiFunctionsDidascalia}`;

    // Tasto di attivazione in alto per i Guest
    inlineKeyboard.push([{ text: "🚀 Registrati e Attiva AI", url: registerUrl }]);
} else {
    // ━━━ VERSIONE PRO (Stakeholder attivo) ━━━
    messageText = `✨ <b>Bentornato, ${customerName}!</b>\n━━━━━━━━━━━━━━━━━━━━\nIl tuo profilo <b>Pro</b> è attivo.\n\n✅ <b>FUNZIONI AI OPERATIVE:</b>\n${aiFunctionsDidascalia}`;

    // Tasto Dashboard in alto per i Pro
    inlineKeyboard.push([{ text: "🖥️ Dashboard TrinAi (Funzioni Pro)", url: dashboardUrl }]);

    // Tasti Operativi PRO (Acquista e Booking MiniApp)
    inlineKeyboard.push([
        { text: "🛒 ACQUISTA", callback_data: "u_CALC" },
        { text: "📅 BOOKING", web_app: { url: `${BASE_APP_URL}/booking.html${ashToken}` } }
    ]);
}

// Integrazione Informativa Privacy e Note Legali
messageText += `\n\n🛡️ <b>PRIVACY:</b>\nAccetti il trattamento dei dati tecnici secondo l' <a href="${privacyUrl}\">Informativa Privacy</a>. \n\n⚠️ <b>GESTIONE DATI:</b>\nUsa il tasto Reset in basso per pulire la sessione bot. Per eliminazione completa account e dati sensibili, procedi su <b>TrinAi</b>.`;

// 6. STRUTTURA TASTIERA COMUNE (Navigazione)
inlineKeyboard.push([
    { text: "📦 Prodotti", callback_data: "g_PRO" },
    { text: "🛠️ Servizi", callback_data: "g_SER" }
]);

inlineKeyboard.push([
    offerButton, 
    { text: "🎧 Assistenza", callback_data: "g_CCare" }
]);

inlineKeyboard.push([
    { text: "🗑️ Reset Sessione (Privacy)", callback_data: "u_RESET_SESSION" }
]);

// 7. PAYLOAD PER TELEGRAM
return [{
    json: {
        ...item,
        generated_ash: ash,
        telegramApiPayload: {
            method: "sendMessage",
            chat_id: msg.chat.id,
            text: messageText,
            parse_mode: "HTML",
            disable_web_page_preview: true,
            reply_markup: {
                inline_keyboard: inlineKeyboard
            }
        }
    }
}];

// ═══════════════════════════════════════════════════════════════
// NODO: Delete_Telegram_Message
// DESC: Prepara il payload per eliminare un messaggio specifico
