// 2. RIGENERAZIONE ASH (Per il tasto Registrazione)
const SECRET_KEY = 'TrinAI-Autorize-Transaction-2=2&';
const WEBHOOK_ID = 'e353fd8a-62fb-4203-a2a7-20369d832e00';
const timestamp = Date.now().toString();
const payload = `${chatId}|${timestamp}|${WEBHOOK_ID}`;

function generateSignature(str, key) {
    let hash = 0;
    const combined = str + key;
    for (let i = 0; i < combined.length; i++) {
        const char = combined.charCodeAt(i);
        hash = ((hash << 5) - hash) + char;
        hash = hash & hash; 
    }
    return Math.abs(hash).toString(16);
}

const signature = generateSignature(payload, SECRET_KEY);
const ash = `${Buffer.from(payload).toString('base64')}.${signature}`;
const registerUrl = `https://dashboard.trinai.it/register?ash=${ash}`;

// 3. DEFINIZIONE TESTO (Italiano + Disclaimer Internazionale se serve)
const agentName = config.identity?.agent_name || "Assistente Virtuale";
let intlDisclaimer = !userLang.startsWith('it') ? "🌍 <i>Catalog unavailable. Use buttons to retry or register.</i>\n━━━━━━━━━━━━━━━━━━━━\n\n" : "";

const messageText = `
${intlDisclaimer}⚠️ <b>Servizio temporaneamente limitato</b>
━━━━━━━━━━━━━━━━━━━━
Gentile utente, sono <b>${agentName}</b>. 

Mi scuso, ma al momento non riesco a caricare l'elenco dei Prodotti e Servizi richiesti. Potrebbe trattarsi di un aggiornamento del database in corso.

Puoi riprovare tra qualche istante o procedere ora alla registrazione per attivare le mie funzioni AI avanzate.

━━━━━━━━━━━━━━━━━━━━
👇 <b>Scegli come procedere:</b>`;

// 4. OUTPUT PER TELEGRAM (editMessageText)
return [{
    json: {
        ...item,
        telegramApiPayload: {
            method: "editMessageText",
            chat_id: chatId,
            message_id: messageId, // Fondamentale per l'edit
            text: messageText,
            parse_mode: "HTML",
            reply_markup: {
                inline_keyboard: [
                    // Riga 1: Registrazione
                    [{ text: "🚀 Registrati e Attiva AI", url: registerUrl }],
                    // Riga 2: Navigazione (Riprova)
                    [
                        { text: "📦 Prodotti", callback_data: "g_PRO" },
                        { text: "🛠️ Servizi", callback_data: "g_SER" }
                    ],
                    // Riga 3: Assistenza
                    [{ text: "🎧 Assistenza (Ticket)", callback_data: "g_CCare" }]
                ]
            }
        }
    }
