// ═══════════════════════════════════════════════════════════════
// NODO: Extract_Pro_Catalog
// DESC: Navigazione prodotti con gestione dinamica catalogo vuoto
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const catalog = item.service_catalog_setup?.categories || [];
const owner = item.owner_data || {};
const body = item.body.callback_query || {};
const chatId = body.from.id;
const messageId = body.message.message_id;

// 1. FILTRAGGIO CHIRURGICO (Macro PRO + Blueprint Ready)
let activeProducts = [];
catalog.forEach(category => {
    if (category.macrocategories === "PRO" && category.subcategories) {
        category.subcategories.forEach(sub => {
            if (sub.blueprint_ready === true) {
                activeProducts.push({
                    name: sub.short_name || sub.name,
                    callback: `g_PRO_DET_${sub.callback_data}`
                });
            }
        });
    }
});

const agentName = owner.customer_bot_config?.identity?.agent_name || "Assistente";
let msgText = "";
let inlineKeyboard = [];

// 2. LOGICA DI OUTPUT DIFFERENZIATA
if (activeProducts.length > 0) {
    // --- CASO: PRODOTTI DISPONIBILI ---
    msgText = `
📦 <b>CATALOGO PRODOTTI</b>
━━━━━━━━━━━━━━━━━━━━
Gentile utente, sono <b>${agentName}</b>. Ecco le soluzioni pronte all'uso che abbiamo selezionato per te.

Seleziona un elemento per approfondire o richiedere una consulenza dedicata:`;

    // Costruzione tastiera a 2 colonne
    for (let i = 0; i < activeProducts.length; i += 2) {
        let row = [];
        row.push({ text: activeProducts[i].name, callback_data: activeProducts[i].callback });
        if (activeProducts[i + 1]) {
            row.push({ text: activeProducts[i + 1].name, callback_data: activeProducts[i + 1].callback });
        }
        inlineKeyboard.push(row);
    }
} else {
    // --- CASO: CATALOGO VUOTO (Messaggio "Caldo") ---
    msgText = `
📦 <b>CATALOGO IN AGGIORNAMENTO</b>
━━━━━━━━━━━━━━━━━━━━
Gentile utente, sono <b>${agentName}</b>. 

In questo momento stiamo rifinendo i dettagli tecnici dei nostri prodotti per garantirti la massima qualità possibile. 

<b>Cosa puoi fare?</b>
• Torna tra poco per scoprire le novità.
• Registrati ora per ricevere una notifica non appena il catalogo sarà online.
• Contattaci direttamente per richieste urgenti.`;
}

// 3. TASTI DI NAVIGAZIONE FISSI
inlineKeyboard.push([{ text: "⬅️ Torna al Menu Principale", callback_data: "m_c_start" }]);

// 4. GENERAZIONE PAYLOAD (editMessageText)
return [{
    json: {
        ...item,
        found_products_count: activeProducts.length,
        telegramApiPayload: {
            method: "editMessageText",
            chat_id: chatId,
            message_id: messageId,
            text: msgText,
            parse_mode: "HTML",
            reply_markup: {
                inline_keyboard: inlineKeyboard
            }
        }
    }
}];

