// ═══════════════════════════════════════════════════════════════
// NODO: Prepare_Detail_View
// DESC: Gestione universale Dettaglio PRO e SER con Handoff ID
// ═══════════════════════════════════════════════════════════════

const item = $input.first().json;
const frag = item.fragment || {};
const body = item.body || {};
const owner = item.owner_data || {};

// 1. IDENTIFICATIVI
const chatId = body.callback_query?.from?.id;
const messageId = body.callback_query?.message?.message_id;
const callbackData = body.callback_query?.data || "";

// 2. DETERMINAZIONE TIPO (PRO vs SER)
const isProduct = callbackData.startsWith('g_PRO');
const typeLabel = isProduct ? "PRODOTTO" : "SERVIZIO";
const typeIcon = isProduct ? "📦" : "🛠️";
const backTarget = isProduct ? "g_PRO" : "g_SER";

// ESTRAZIONE GHOST_ID (es. SVC_05S3EKTT)
const ghost_id = frag.fragment_id.split('-')[1] || frag.fragment_id;

// 3. COSTRUZIONE TESTO DINAMICO
let msgText = `${typeIcon} <b>${frag.title.toUpperCase()}</b>\n`;
msgText += `━━━━━━━━━━━━━━━━━━━━\n\n`;

// Header variabile basato sul tipo
const valueHeader = isProduct ? "PERCHÉ SCEGLIERLO" : "VALORE STRATEGICO";
msgText += `💡 <b>${valueHeader}:</b>\n<i>${frag.answer_fragment}</i>\n\n`;

// Sezione Dettagli (Sections)
if (frag.sections && frag.sections.length > 0) {
    const detailLabel = isProduct ? "SPECIFICHE TECNICHE" : "DETTAGLI OPERATIVI";
    msgText += `🔍 <b>${detailLabel}:</b>\n`;

    frag.sections.forEach((sec, index) => {
        msgText += `\n<b>${index + 1}. ${sec.question}</b>\n`;
        msgText += `   └ ${sec.answer}\n`;

        if (sec.analogy) {
            const analogyIcon = isProduct ? "🧩" : "⚙️";
            msgText += `   ${analogyIcon} <i>Focus: ${sec.analogy}</i>\n`;
        }
    });
}

msgText += `\n━━━━━━━━━━━━━━━━━━━━\n`;
msgText += `✨ <b>IN SINTESI:</b>\n<i>${frag.summary}</i>`;

// 4. TASTIERA DI CONTROLLO
const inlineKeyboard = [
    // TASTO ASSISTENZA CON ID PRODOTTO/SERVIZIO
    [{ text: "🎧 Parla con un esperto", callback_data: `g_CCall_${ghost_id}` }],
    // NAVIGAZIONE
    [
        { text: "⬅️ Torna alla Lista", callback_data: backTarget },
        { text: "🏠 Menu", callback_data: "m_c_start" }
    ]
];

// 5. OUTPUT PER TELEGRAM
return [{
    json: {
